func:
msg.payload = "Extracted Host Spec Data: \n" + msg.payload.toString().substring(0, 500);
// The MCP protocol expects the result to be correctly wrapped, which the MCP Return node usually handles.
return msg;

msg.payload = {
    unitid: msg.payload.unitid,
    fc: 3,
    address: msg.payload.address,
    quantity: msg.payload.quantity
};
return msg;

let timestamp = new Date().toISOString();
let values = msg.payload.join(",");
msg.payload = `${timestamp},${values}\n`;
return msg;

msg.payload = {
    timestamp: new Date().toISOString(),
    device: "PLC-01",
    registers: msg.payload,
    status: "ok"
};
return msg;

msg.topic = `CREATE TABLE IF NOT EXISTS modbus_readings (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    timestamp TEXT NOT NULL,
    temperature REAL,
    pressure REAL,
    motor_speed INTEGER,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
)`;
return msg;

let temp = msg.payload[0] / 10;
let pressure = msg.payload[1] / 100;
let speed = msg.payload[2];
msg.topic = `INSERT INTO modbus_readings (timestamp, temperature, pressure, motor_speed)
             VALUES ('${new Date().toISOString()}', ${temp}, ${pressure}, ${speed})`;
return msg;

// Last 100 readings
msg.topic = "SELECT * FROM modbus_readings ORDER BY id DESC LIMIT 100";
return msg;

flow.set("simData", {
    timestamp: new Date().toISOString(),
    registers: msg.payload,
    status: "Active"
});
return msg;

// Initialize Node Context state for dynamic patterns
let count = context.get("count") || 0;
let temp = context.get("temp") || 200;

// 1. Counter (0 to 1000 then loop)
count = (count + 1) % 1000;

// 2. Sine Wave (simulating a cyclic process like 0-100%)
// Scale sine wave from -1..1 to 0..1000
let sineValue = Math.round((Math.sin(count * 0.2) + 1) * 500);

// 3. Random Noise (simulating pressure jitter 500 +/- 20)
let randomJitter = 500 + Math.floor(Math.random() * 40) - 20;

// 4. Sawtooth Wave (0 to 100 ramp up and drop)
let sawtooth = count % 100;

// 5. Simulated Temperature (Drifts slowly between 150 and 250)
temp = temp + (Math.random() > 0.5 ? 1 : -1);
if (temp > 250) temp = 250;
if (temp < 150) temp = 150;

// Save state for the next tick
context.set("count", count);
context.set("temp", temp);

// Combine into an array of 5 holding registers (16-bit integers)
msg.payload = [count, sineValue, randomJitter, sawtooth, temp];
return msg;

let regs = msg.payload;

// We translate the raw Modbus arrays into a friendly SCADA schema
let data = {
    timestamp: new Date().toISOString(),
    rawRegisters: regs,
    sensors: {
        cycleCount: regs[0],
        sineWaveValue: regs[1],
        pressureNoise: regs[2],
        sawtoothPattern: regs[3],
        temperatureC: +(regs[4] / 10).toFixed(1) // E.g., translates 215 back to 21.5 C
    },
    status: "Active"
};

// Save globally to this flow
flow.set("simData", data);
return msg;
